// =============================================
// LingNow Prototype Business Logic Engine
// Generated by UiDesignerAgent (Java-controlled)
// MOCK_DATA_JSON is replaced at runtime.
// =============================================
document.addEventListener('alpine:init', function () {
    Alpine.store('app', {
        // ---- State ----
        activeTab: '#INDEX',
        searchQuery: '',
        isLoggedIn: false,
        currentUser: null,
        selectedPost: null,
        showAuthModal: false,
        showPostModal: false,
        showNotif: false,
        toastMessage: '',
        toastVisible: false,
        newPostTitle: '',
        newPostContent: '',
        newPostTags: '',
        commentDraft: {},

        // ---- Raw Data (replaced at runtime) ----
        posts: (function () {
            try {
                var raw = MOCK_DATA_JSON;
                if (!Array.isArray(raw)) {
                    var found = null;
                    for (var k in raw) {
                        if (Array.isArray(raw[k])) {
                            found = raw[k];
                            break;
                        }
                    }
                    raw = found || [];
                }
                return raw.map(function (p, i) {
                    return Object.assign({
                        id: i + 1,
                        likes: Math.floor(Math.random() * 200) + 10,
                        liked: false,
                        views: Math.floor(Math.random() * 5000) + 100,
                        comments: [],
                        tags: []
                    }, p);
                });
            } catch (e) {
                return [];
            }
        })(),

        notifications: [
            {id: 1, type: 'comment', text: '后端老王 回复了你的评论。', time: '5分钟前', read: false},
            {id: 2, type: 'follow', text: '云原生小赵 关注了你。', time: '20分钟前', read: false},
            {id: 3, type: 'like', text: '数据库达人 点赞了你的文章。', time: '1小时前', read: true}
        ],

        // ---- Computed ----
        get filteredPosts() {
            if (!this.searchQuery) return this.posts;
            var q = this.searchQuery.toLowerCase();
            return this.posts.filter(function (p) {
                return JSON.stringify(p).toLowerCase().indexOf(q) !== -1;
            });
        },
        get unreadCount() {
            return this.notifications.filter(function (n) {
                return !n.read;
            }).length;
        },

        // ---- Auth ----
        login: function (username, password) {
            this.isLoggedIn = true;
            this.currentUser = {
                name: username || '晨曦工程师',
                avatar: 'CE',
                bio: '前端架构师，专注于工程化与性能优化。'
            };
            this.showAuthModal = false;
            this.toast('欢迎回来，' + (username || '晨曦工程师') + '！');
        },
        logout: function () {
            this.isLoggedIn = false;
            this.currentUser = null;
            this.toast('已退出登录');
        },

        // ---- Browse ----
        openPost: function (post) {
            this.selectedPost = post;
            if (!this.selectedPost.comments) this.selectedPost.comments = [];
            this.commentDraft[post.id] = '';
            this.activeTab = '#PostDetail';
            window.scrollTo(0, 0);
        },
        backToFeed: function () {
            this.activeTab = '#INDEX';
            this.selectedPost = null;
        },

        // ---- Like ----
        likePost: function (post) {
            if (!this.isLoggedIn) {
                this.showAuthModal = true;
                return;
            }
            post.liked = !post.liked;
            post.likes += post.liked ? 1 : -1;
        },

        // ---- Comment ----
        submitComment: function (post) {
            if (!this.isLoggedIn) {
                this.showAuthModal = true;
                return;
            }
            var text = (this.commentDraft[post.id] || '').trim();
            if (!text) {
                this.toast('请输入评论内容');
                return;
            }
            if (!post.comments) post.comments = [];
            post.comments.push({
                id: Date.now(),
                author: this.currentUser.name,
                avatar: this.currentUser.avatar,
                text: text,
                time: '刚刚',
                likes: 0
            });
            this.commentDraft[post.id] = '';
            this.toast('评论发布成功！');
        },

        // ---- Create Post ----
        submitPost: function () {
            if (!this.isLoggedIn) {
                this.showAuthModal = true;
                return;
            }
            if (!this.newPostTitle.trim()) {
                this.toast('请输入标题');
                return;
            }
            var newPost = {
                id: Date.now(),
                title: this.newPostTitle,
                content: this.newPostContent || '（暂无正文）',
                tags: this.newPostTags ? this.newPostTags.split(',').map(function (t) {
                    return t.trim();
                }) : [],
                author: this.currentUser.name,
                likes: 0, liked: false, views: 1, comments: [],
                time: '刚刚'
            };
            this.posts.unshift(newPost);
            this.newPostTitle = '';
            this.newPostContent = '';
            this.newPostTags = '';
            this.showPostModal = false;
            this.toast('帖子发布成功！');
        },

        // ---- Notifications ----
        markAllRead: function () {
            this.notifications.forEach(function (n) {
                n.read = true;
            });
            this.toast('已全部标为已读');
        },

        // ---- Navigate ----
        nav: function (tab) {
            this.activeTab = tab;
        },

        // ---- Toast ----
        toast: function (msg) {
            this.toastMessage = msg;
            this.toastVisible = true;
            var self = this;
            setTimeout(function () {
                self.toastVisible = false;
            }, 3000);
        }
    });
});
